#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum ApplyMode {
    DryRun,
    Apply,
}

impl ApplyMode {
    fn is_dry_run(self) -> bool {
        matches!(self, Self::DryRun)
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum CommitMode {
    Auto,
    Skip,
}

impl CommitMode {
    fn is_disabled(self) -> bool {
        matches!(self, Self::Skip)
    }
}

#[derive(Debug, Clone, Copy)]
struct ConfigMutationOptions {
    apply_mode: ApplyMode,
    commit_mode: CommitMode,
    quiet: bool,
}

#[derive(Debug, Clone, Copy)]
struct ExportProfileCreateRequest<'a> {
    format: ExportProfileFormatArg,
    query: Option<&'a str>,
    query_json: Option<&'a str>,
    path: &'a Path,
    title: Option<&'a str>,
    author: Option<&'a str>,
    toc: Option<EpubTocStyle>,
    backlinks: bool,
    frontmatter: bool,
    pretty: bool,
    graph_format: Option<GraphExportFormat>,
}

#[derive(Debug, Clone, Copy)]
enum ConfigValueUpdate<T> {
    Keep,
    Set(T),
    Clear,
}

impl<T> ConfigValueUpdate<T> {
    fn has_change(self) -> bool {
        !matches!(self, Self::Keep)
    }
}

#[derive(Debug, Clone, Copy)]
enum BoolConfigUpdate {
    Keep,
    SetTrue,
    Clear,
}

impl BoolConfigUpdate {
    fn has_change(self) -> bool {
        !matches!(self, Self::Keep)
    }
}

