fn checkpoint_rows(records: &[CheckpointRecord]) -> Vec<Value> {
    records
        .iter()
        .map(|record| {
            serde_json::json!({
                "id": record.id,
                "name": record.name,
                "source": record.source,
                "created_at": record.created_at,
                "note_count": record.note_count,
                "orphan_notes": record.orphan_notes,
                "stale_notes": record.stale_notes,
                "resolved_links": record.resolved_links,
            })
        })
        .collect()
}

fn change_rows(report: &ChangeReport) -> Vec<Value> {
    let mut rows = Vec::new();
    append_change_rows(&mut rows, &report.anchor, ChangeKind::Note, &report.notes);
    append_change_rows(&mut rows, &report.anchor, ChangeKind::Link, &report.links);
    append_change_rows(
        &mut rows,
        &report.anchor,
        ChangeKind::Property,
        &report.properties,
    );
    append_change_rows(
        &mut rows,
        &report.anchor,
        ChangeKind::Embedding,
        &report.embeddings,
    );
    rows
}

fn append_change_rows(rows: &mut Vec<Value>, anchor: &str, kind: ChangeKind, items: &[ChangeItem]) {
    let kind_name = serde_json::to_value(kind)
        .expect("change kind should serialize")
        .as_str()
        .expect("change kind should serialize to a string")
        .to_string();
    for item in items {
        rows.push(serde_json::json!({
            "anchor": anchor,
            "kind": kind_name,
            "path": item.path,
            "status": item.status,
        }));
    }
}

// ────────────────────────────────────────────────────────────────────────────
// vulcan status
// ────────────────────────────────────────────────────────────────────────────

#[derive(Debug, Clone, Serialize)]
struct VaultStatusReport {
    vault_root: String,
    note_count: usize,
    attachment_count: usize,
    last_scan: Option<String>,
    cache_bytes: u64,
    git_branch: Option<String>,
    git_dirty: bool,
    git_staged: usize,
    git_unstaged: usize,
    git_untracked: usize,
}

fn run_status_command(paths: &VaultPaths) -> Result<VaultStatusReport, CliError> {
    let cache = inspect_cache(paths).map_err(CliError::operation)?;

    let last_scan = {
        use vulcan_core::CacheDatabase;
        let db = CacheDatabase::open(paths).ok();
        db.and_then(|db| {
            db.connection()
                .query_row("SELECT MAX(indexed_at) FROM documents", [], |row| {
                    row.get::<_, Option<String>>(0)
                })
                .ok()
                .flatten()
        })
    };

    let (git_branch, git_dirty, git_staged, git_unstaged, git_untracked) =
        if vulcan_core::is_git_repo(paths.vault_root()) {
            match git_status(paths.vault_root()) {
                Ok(status) => {
                    let branch = {
                        let output = ProcessCommand::new("git")
                            .arg("-C")
                            .arg(paths.vault_root())
                            .args(["rev-parse", "--abbrev-ref", "HEAD"])
                            .output()
                            .ok();
                        output.and_then(|o| {
                            if o.status.success() {
                                String::from_utf8(o.stdout)
                                    .ok()
                                    .map(|s| s.trim().to_string())
                                    .filter(|s| !s.is_empty())
                            } else {
                                None
                            }
                        })
                    };
                    (
                        branch,
                        !status.clean,
                        status.staged.len(),
                        status.unstaged.len(),
                        status.untracked.len(),
                    )
                }
                Err(_) => (None, false, 0, 0, 0),
            }
        } else {
            (None, false, 0, 0, 0)
        };

    Ok(VaultStatusReport {
        vault_root: paths.vault_root().display().to_string(),
        note_count: cache.notes,
        attachment_count: cache.attachments,
        last_scan,
        cache_bytes: cache.database_bytes,
        git_branch,
        git_dirty,
        git_staged,
        git_unstaged,
        git_untracked,
    })
}

fn print_status_report(
    output: OutputFormat,
    report: &VaultStatusReport,
    use_color: bool,
) -> Result<(), CliError> {
    match output {
        OutputFormat::Json => print_json(report),
        OutputFormat::Human | OutputFormat::Markdown => {
            let palette = AnsiPalette::new(use_color);
            println!("Vault:      {}", report.vault_root);
            println!(
                "Notes:      {}  attachments: {}",
                report.note_count, report.attachment_count
            );
            println!("Cache:      {} bytes", report.cache_bytes);
            if let Some(last_scan) = &report.last_scan {
                println!("Last scan:  {last_scan}");
            } else {
                println!("Last scan:  {}", palette.dim("never"));
            }
            if let Some(branch) = &report.git_branch {
                let dirty_flag = if report.git_dirty {
                    format!(
                        " {}",
                        palette.yellow(&format!(
                            "(dirty: {} staged, {} unstaged, {} untracked)",
                            report.git_staged, report.git_unstaged, report.git_untracked
                        ))
                    )
                } else {
                    format!(" {}", palette.green("(clean)"))
                };
                println!("Git:        {branch}{dirty_flag}");
            } else {
                println!("Git:        {}", palette.dim("not a git repository"));
            }
            Ok(())
        }
    }
}

// ────────────────────────────────────────────────────────────────────────────
// graph export
// ────────────────────────────────────────────────────────────────────────────

fn print_graph_export_report(
    output: OutputFormat,
    report: &vulcan_core::GraphExportReport,
    format: GraphExportFormat,
) -> Result<(), CliError> {
    match output {
        OutputFormat::Json => print_json(report),
        OutputFormat::Human | OutputFormat::Markdown => {
            match format {
                GraphExportFormat::Json => {
                    print_json(report)?;
                }
                GraphExportFormat::Dot => {
                    println!("digraph vault {{");
                    for node in &report.nodes {
                        let label = node.path.trim_end_matches(".md").replace('"', "\\\"");
                        let id = node.path.replace('"', "\\\"");
                        println!("  \"{id}\" [label=\"{label}\"];");
                    }
                    for edge in &report.edges {
                        let src = edge.source.replace('"', "\\\"");
                        let tgt = edge.target.replace('"', "\\\"");
                        println!("  \"{src}\" -> \"{tgt}\";");
                    }
                    println!("}}");
                }
                GraphExportFormat::Graphml => {
                    println!("<?xml version=\"1.0\" encoding=\"UTF-8\"?>");
                    println!("<graphml xmlns=\"http://graphml.graphdrawing.org/graphml\">");
                    println!("  <graph id=\"vault\" edgedefault=\"directed\">");
                    for node in &report.nodes {
                        let id = node.path.replace('"', "&quot;");
                        println!("    <node id=\"{id}\"/>");
                    }
                    for (i, edge) in report.edges.iter().enumerate() {
                        let src = edge.source.replace('"', "&quot;");
                        let tgt = edge.target.replace('"', "&quot;");
                        println!("    <edge id=\"e{i}\" source=\"{src}\" target=\"{tgt}\"/>");
                    }
                    println!("  </graph>");
                    println!("</graphml>");
                }
            }
            Ok(())
        }
    }
}

// ────────────────────────────────────────────────────────────────────────────
// template show
// ────────────────────────────────────────────────────────────────────────────

#[derive(Debug, Clone, Serialize)]
struct TemplateShowReport {
    name: String,
    source: String,
    path: String,
    content: String,
}

fn run_template_show_command(
    paths: &VaultPaths,
    name: &str,
    output: OutputFormat,
) -> Result<(), CliError> {
    let config = load_vault_config(paths).config;
    let templates = discover_templates(
        paths,
        config.templates.obsidian_folder.as_deref(),
        config.templates.templater_folder.as_deref(),
    )?;
    let template = resolve_template_file(paths, &templates.templates, name)?;
    let absolute = &template.absolute_path;
    let content = fs::read_to_string(absolute).map_err(CliError::operation)?;
    let report = TemplateShowReport {
        name: template.name.clone(),
        source: template.source.to_string(),
        path: template.display_path.clone(),
        content: content.clone(),
    };
    match output {
        OutputFormat::Json => print_json(&report),
        OutputFormat::Human | OutputFormat::Markdown => {
            println!("Name:   {}", report.name);
            println!("Source: {}", report.source);
            println!("Path:   {}", report.path);
            println!();
            print!("{content}");
            Ok(())
        }
    }
}

// ────────────────────────────────────────────────────────────────────────────
// MCP server
// ────────────────────────────────────────────────────────────────────────────

#[derive(Debug, Clone)]
struct McpPermissionSelection {
    name: String,
    profile: PermissionProfile,
}

#[allow(clippy::struct_excessive_bools)]
#[derive(Debug, Clone, Default)]
struct McpToolPermissionRequirement {
    read: bool,
    write: bool,
    refactor: bool,
    git: bool,
    network: bool,
    index: bool,
    execute: bool,
    config: Option<ConfigPermissionMode>,
}

impl McpToolPermissionRequirement {
    const fn read() -> Self {
        Self {
            read: true,
            ..Self::empty()
        }
    }

    const fn write() -> Self {
        Self {
            write: true,
            ..Self::empty()
        }
    }

    const fn refactor() -> Self {
        Self {
            refactor: true,
            ..Self::empty()
        }
    }

    const fn git() -> Self {
        Self {
            git: true,
            ..Self::empty()
        }
    }

    const fn network() -> Self {
        Self {
            network: true,
            ..Self::empty()
        }
    }

    const fn index() -> Self {
        Self {
            index: true,
            ..Self::empty()
        }
    }

    const fn execute() -> Self {
        Self {
            execute: true,
            ..Self::empty()
        }
    }

    const fn config_read() -> Self {
        Self {
            config: Some(ConfigPermissionMode::Read),
            ..Self::empty()
        }
    }

    const fn config_write() -> Self {
        Self {
            config: Some(ConfigPermissionMode::Write),
            ..Self::empty()
        }
    }

    const fn execute_write() -> Self {
        Self {
            execute: true,
            write: true,
            ..Self::empty()
        }
    }

    const fn empty() -> Self {
        Self {
            read: false,
            write: false,
            refactor: false,
            git: false,
            network: false,
            index: false,
            execute: false,
            config: None,
        }
    }
}

fn run_mcp_server(paths: &VaultPaths, requested_profile: Option<&str>) -> Result<(), CliError> {
    use std::io::BufRead;

    let exe = std::env::current_exe().map_err(CliError::operation)?;
    let vault_str = paths.vault_root().to_string_lossy().into_owned();
    let permissions = resolve_mcp_permission_selection(paths, requested_profile)?;
    let tools = build_mcp_tool_definitions_with_paths();

    let stdin = io::stdin();
    for line in stdin.lock().lines() {
        let line = line.map_err(CliError::operation)?;
        let line = line.trim();
        if line.is_empty() {
            continue;
        }
        let request: Value = match serde_json::from_str(line) {
            Ok(v) => v,
            Err(e) => {
                let response = serde_json::json!({
                    "jsonrpc": "2.0",
                    "id": null,
                    "error": { "code": -32700, "message": format!("Parse error: {e}") }
                });
                println!("{}", serde_json::to_string(&response).unwrap_or_default());
                continue;
            }
        };

        let id = request.get("id").cloned().unwrap_or(Value::Null);
        let method = request.get("method").and_then(Value::as_str).unwrap_or("");
        let params = request.get("params");

        let result: Result<Value, (i64, String)> = match method {
            "initialize" => Ok(serde_json::json!({
                "protocolVersion": "2024-11-05",
                "capabilities": { "tools": {} },
                "serverInfo": { "name": "vulcan", "version": env!("CARGO_PKG_VERSION") }
            })),
            "notifications/initialized" => {
                // No response needed for notifications
                continue;
            }
            "tools/list" => {
                let list: Vec<Value> = tools
                    .iter()
                    .filter(|tool| mcp_tool_visible(tool, &permissions.profile))
                    .map(|t| {
                        serde_json::json!({
                            "name": t.name,
                            "description": t.description,
                            "inputSchema": t.input_schema
                        })
                    })
                    .collect();
                Ok(serde_json::json!({ "tools": list }))
            }
            "tools/call" => {
                let tool_name = params
                    .and_then(|p| p.get("name"))
                    .and_then(Value::as_str)
                    .unwrap_or("");
                let arguments = params
                    .and_then(|p| p.get("arguments"))
                    .and_then(Value::as_object)
                    .cloned()
                    .unwrap_or_default();

                match mcp_dispatch_tool(
                    &exe,
                    &vault_str,
                    tool_name,
                    &arguments,
                    &tools,
                    &permissions,
                ) {
                    Ok(text) => Ok(serde_json::json!({
                        "content": [{ "type": "text", "text": text }]
                    })),
                    Err(e) => Err((-32000, e)),
                }
            }
            _ => Err((-32601, format!("Method not found: {method}"))),
        };

        let response = match result {
            Ok(value) => serde_json::json!({
                "jsonrpc": "2.0",
                "id": id,
                "result": value
            }),
            Err((code, message)) => serde_json::json!({
                "jsonrpc": "2.0",
                "id": id,
                "error": { "code": code, "message": message }
            }),
        };
        println!("{}", serde_json::to_string(&response).unwrap_or_default());
    }
    Ok(())
}

struct McpToolWithPath {
    name: String,
    description: String,
    input_schema: Value,
    /// Command path segments, e.g. `["note", "get"]`
    command_path: Vec<String>,
    /// Which argument IDs are positional (not flags)
    positional_ids: Vec<String>,
}

fn build_mcp_tool_definitions_with_paths() -> Vec<McpToolWithPath> {
    let tree = cli_command_tree();
    let mut tools = Vec::new();
    for subcommand in tree.get_subcommands().filter(|s| !s.is_hide_set()) {
        collect_mcp_tools_inner(subcommand, Vec::new(), &mut tools);
    }
    tools
}

fn collect_mcp_tools_inner(
    command: &clap::Command,
    mut prefix: Vec<String>,
    tools: &mut Vec<McpToolWithPath>,
) {
    prefix.push(command.get_name().to_string());
    let subs: Vec<_> = command
        .get_subcommands()
        .filter(|s| !s.is_hide_set())
        .collect();
    if subs.is_empty() {
        let positional_ids: Vec<String> = command
            .get_arguments()
            .filter(|a| a.is_positional() && !a.is_global_set())
            .map(|a| a.get_id().to_string())
            .collect();
        tools.push(McpToolWithPath {
            name: tool_name_from_path(&prefix),
            description: command
                .get_about()
                .map_or_else(|| prefix.join(" "), ToString::to_string),
            input_schema: command_input_schema(command),
            command_path: prefix,
            positional_ids,
        });
        return;
    }
    for sub in subs {
        collect_mcp_tools_inner(sub, prefix.clone(), tools);
    }
}

fn mcp_dispatch_tool(
    exe: &Path,
    vault: &str,
    tool_name: &str,
    arguments: &serde_json::Map<String, Value>,
    tools: &[McpToolWithPath],
    permissions: &McpPermissionSelection,
) -> Result<String, String> {
    let tool = tools
        .iter()
        .find(|t| t.name == tool_name)
        .ok_or_else(|| format!("unknown tool: {tool_name}"))?;

    if let Some(message) = mcp_tool_permission_denial(tool, arguments, permissions) {
        return Err(message);
    }

    let mut args: Vec<OsString> = vec![
        "--vault".into(),
        vault.into(),
        "--output".into(),
        "json".into(),
    ];

    // Add command path segments
    for segment in &tool.command_path {
        args.push(segment.into());
    }

    // Positional args first (in order they appear in positional_ids)
    for pos_id in &tool.positional_ids {
        if let Some(val) = arguments.get(pos_id) {
            let s = mcp_value_to_string(val);
            if !s.is_empty() {
                args.push(s.into());
            }
        }
    }

    // Then flag args
    for (key, val) in arguments {
        if tool.positional_ids.contains(key) {
            continue; // already handled
        }
        // Skip null/false optional flags
        match val {
            Value::Null | Value::Bool(false) => continue,
            Value::Bool(true) => {
                let flag = format!("--{}", key.replace('_', "-"));
                args.push(flag.into());
                continue;
            }
            _ => {}
        }
        let flag = format!("--{}", key.replace('_', "-"));
        args.push(flag.into());
        args.push(mcp_value_to_string(val).into());
    }

    let output = ProcessCommand::new(exe)
        .args(&args)
        .output()
        .map_err(|e| format!("failed to run tool: {e}"))?;

    let stdout = String::from_utf8_lossy(&output.stdout).into_owned();
    let stderr = String::from_utf8_lossy(&output.stderr).into_owned();

    if !output.status.success() && stdout.trim().is_empty() {
        return Err(if stderr.trim().is_empty() {
            format!("tool exited with status {}", output.status)
        } else {
            stderr.trim().to_string()
        });
    }

    Ok(stdout)
}

fn resolve_mcp_permission_selection(
    paths: &VaultPaths,
    requested_profile: Option<&str>,
) -> Result<McpPermissionSelection, CliError> {
    let resolved =
        resolve_permission_profile(paths, requested_profile).map_err(permission_error_to_cli)?;
    ensure_mcp_permission_profile_supported(&resolved.name, &resolved.profile)?;

    Ok(McpPermissionSelection {
        name: resolved.name,
        profile: resolved.profile,
    })
}

fn ensure_mcp_permission_profile_supported(
    name: &str,
    profile: &PermissionProfile,
) -> Result<(), CliError> {
    if profile.read.is_scoped() || profile.write.is_scoped() || profile.refactor.is_scoped() {
        return Err(CliError::operation(format!(
            "permission profile `{name}` uses scoped path rules; `vulcan mcp` currently supports only `all` or `none` for read/write/refactor"
        )));
    }

    if !profile.network.domain_allowlist().is_empty() {
        return Err(CliError::operation(format!(
            "permission profile `{name}` uses a network domain allowlist; `vulcan mcp` does not enforce domain-scoped network access yet"
        )));
    }

    if matches!(profile.execute, PermissionMode::Allow) && !profile.is_unrestricted() {
        return Err(CliError::operation(format!(
            "permission profile `{name}` enables execute; `vulcan mcp` currently supports execute only under the unrestricted profile"
        )));
    }

    Ok(())
}

fn mcp_tool_visible(tool: &McpToolWithPath, profile: &PermissionProfile) -> bool {
    if profile.is_unrestricted() {
        return true;
    }
    mcp_profile_allows(profile, &mcp_tool_list_requirement(tool)).is_ok()
}

fn mcp_tool_permission_denial(
    tool: &McpToolWithPath,
    arguments: &serde_json::Map<String, Value>,
    permissions: &McpPermissionSelection,
) -> Option<String> {
    if permissions.profile.is_unrestricted() {
        return None;
    }

    mcp_profile_allows(
        &permissions.profile,
        &mcp_tool_call_requirement(tool, arguments),
    )
    .err()
    .map(|reason| {
        format!(
            "permission denied: tool `{}` requires {reason} under profile `{}`",
            tool.name, permissions.name
        )
    })
}

fn mcp_profile_allows(
    profile: &PermissionProfile,
    requirement: &McpToolPermissionRequirement,
) -> Result<(), &'static str> {
    if requirement.read && !profile.read.is_all() {
        return Err("read access");
    }
    if requirement.write && !profile.write.is_all() {
        return Err("write access");
    }
    if requirement.refactor && !profile.refactor.is_all() {
        return Err("refactor access");
    }
    if requirement.git && !matches!(profile.git, PermissionMode::Allow) {
        return Err("git access");
    }
    if requirement.network && !profile.network.is_allowed() {
        return Err("network access");
    }
    if requirement.index && !matches!(profile.index, PermissionMode::Allow) {
        return Err("index access");
    }
    if requirement.execute && !matches!(profile.execute, PermissionMode::Allow) {
        return Err("execute access");
    }
    match requirement.config {
        Some(ConfigPermissionMode::Read)
            if matches!(profile.config, ConfigPermissionMode::None) =>
        {
            Err("config read access")
        }
        Some(ConfigPermissionMode::Write)
            if !matches!(profile.config, ConfigPermissionMode::Write) =>
        {
            Err("config write access")
        }
        _ => Ok(()),
    }
}

